xhtml:body.xhtml:script:
//
  (function() {
    function size() {
      var w = window.innerWidth, h = window.innerHeight;
      var svg = document.querySelector('svg');
      var fo  = document.querySelector('foreignObject');
      if (svg) { svg.setAttribute('width', w); svg.setAttribute('height', h); svg.setAttribute('viewBox','0 0 '+w+' '+h); }
      if (fo)  { fo.setAttribute('width', w);  fo.setAttribute('height', h); }
    }
    size();
    window.addEventListener('resize', size);

    const BASE = (function() {
      var loc = window.location.href;
      return loc.substring(0, loc.lastIndexOf('/') + 1);
    })();

    // All HTML pages in the repo
    const PAGES = [
      'index.html',
      'ai.html',
      'games.html',
      'movie.html',
      'movies.html',
      'music.html',
      'proxy.html',
      'crunchyroll.html',
      'geometrydash.html',
      'roblox.html'
    ];

    async function fetchPage(name) {
      const res = await fetch(BASE + name + '?t=' + Date.now());
      let text = await res.text();
      // Inject base so external CDN links still work
      const baseTag = '<base href="' + BASE + '">';
      text = /<head[^>]*>/i.test(text)
        ? text.replace(/(<head[^>]*>)/i, '$1' + baseTag)
        : baseTag + text;
      return text;
    }

    (async () => {
      try {
        // 1. Fetch all pages in parallel
        const results = await Promise.all(PAGES.map(p => fetchPage(p).then(html => ({ name: p, html }))));

        // 2. Build a map of filename -> blob URL
        const blobMap = {};
        for (const { name, html } of results) {
          const blob = new Blob([html], { type: 'text/html' });
          blobMap[name] = URL.createObjectURL(blob);
        }

        // 3. Rewrite index.html — replace every src="*.html" and href="*.html"
        //    with the pre-built blob URLs
        let indexHtml = results.find(r => r.name === 'index.html').html;
        for (const [name, blobUrl] of Object.entries(blobMap)) {
          if (name === 'index.html') continue;
          // Replace in src=, href=, and JS strings like 'games.html' / "games.html"
          const escaped = name.replace('.', '\\.');
          indexHtml = indexHtml.replace(new RegExp('([\'"])'  + escaped + '\\1', 'g'), '$1' + blobUrl + '$1');
          indexHtml = indexHtml.replace(new RegExp('(src=[\'"])' + escaped + '([\'"])', 'g'), '$1' + blobUrl + '$2');
          indexHtml = indexHtml.replace(new RegExp('(href=[\'"])' + escaped + '([\'"])', 'g'), '$1' + blobUrl + '$2');
        }

        // 4. Make a fresh blob for the patched index and load it
        const indexBlob = new Blob([indexHtml], { type: 'text/html' });
        const indexUrl = URL.createObjectURL(indexBlob);
        document.getElementById('fm').src = indexUrl;

      } catch(e) {
        console.error('Loader error:', e);
      }
    })();
  })();
//
